\begin{def}
The dimension of a non-empty affine set is defined as the dimension of the subspace parallel to it. (The dimension of $\emptyset$ is $-1$ by convention.)
\end{def}

\begin{def}
Affine sets of dimension 0, 1 and 2 are called points, lines and planes, respectively. An $(n - 1)$-dimensional affine set in $\mathbb{R}^n$ is called a hyperplane.
\end{def}

\begin{def}
Given a subspace $L$ of $\mathbb{R}^n$, the set of vectors $x$ such that $x \perp L$, i.e. $x \perp y$ for every $y \in L$, is called the orthogonal complement of $L$, denoted $L^\perp$.
\end{def}

\begin{thm}
Theorem 1.3. Given \( \beta \in R \) and a non-zero \( b \in R^n \), the set

\[
H = \{ x \mid \langle x, b \rangle = \beta \}
\]

is a hyperplane in \( R^n \). Moreover, every hyperplane may be represented in this way, with \( b \) and \( \beta \) unique up to a common non-zero multiple.
\end{thm}

\begin{def}
In Theorem 1.3, the vector $b$ is called a normal to the hyperplane $H$.
\end{def}

\begin{thm}
Theorem 1.4. Given \( b \in R^m \) and an \( m \times n \) real matrix \( B \), the set

\[
M = \{ x \in R^n \mid Bx = b \}
\]

is an affine set in \( R^n \). Moreover, every affine set may be represented in this way.
\end{thm}

\begin{cor}
\textbf{Corollary 1.4.1.} Every affine subset of \( R^n \) is an intersection of a finite collection of hyperplanes.
\end{cor}

\begin{def}
Given any \( S \subset R^n \) there exists a unique smallest affine set containing \( S \) (namely, the intersection of the collection of affine sets \( M \) such that \( M \supset S \)). This set is called the affine hull of \( S \) and is denoted by \( \text{aff} S \)
\end{def}

 egin{thm}
Theorem. Let $b_0, b_1, \dots, b_m \in \mathbb{R}^n$. Define

\[ L := \operatorname{aff}\{0, b_1 - b_0, \dots, b_m - b_0\}. \]

Then

\[ \operatorname{aff}\{b_0, b_1, \dots, b_m\} = b_0 + L. \]

Moreover, the points $b_0, b_1, \dots, b_m$ are affinely independent if and only if the vectors $b_1 - b_0, \dots, b_m - b_0$ are linearly independent.\end{thm}

 egin{thm}
Let $b_0, b_1, \dots, b_m \in \mathbb{R}^n$ and let $M = \operatorname{aff}\{b_0, b_1, \dots, b_m\}$. Every point $x \in M$ admits a representation

\[ x = \lambda_0 b_0 + \lambda_1 b_1 + \cdots + \lambda_m b_m, \qquad \lambda_0 + \lambda_1 + \cdots + \lambda_m = 1. \]

Moreover, the coefficients $(\lambda_0, \lambda_1, \dots, \lambda_m)$ are unique if and only if the points $b_0, b_1, \dots, b_m$ are affinely independent.\end{thm}

\begin{def}
A single-valued mapping $T:x \to Tx$ from $\mathbb{R}^n$ to $\mathbb{R}^m$ is called an affine transformation if \[ T((1 - \lambda)x + \lambda y) = (1 - \lambda)Tx + \lambda Ty \] for every $x$ and $y$ in $\mathbb{R}^n$ and $\lambda \in \mathbb{R}$.
\end{def}

\begin{thm}
Theorem 1.5. The affine transformations from $R^n$ to $R^m$ are the mappings $T$ of the form $Tx = Ax + a$, where $A$ is a linear transformation and $a \in R^m$.
\end{thm}

\begin{thm}
Let $T : \mathbb{R}^n \to \mathbb{R}^n$ be an affine transformation. If $A$ is invertible, then the inverse mapping $T^{-1}$ is also an affine transformation.
\end{thm}

\begin{thm}
Let $T : \mathbb{R}^n \to \mathbb{R}^m$ be an affine transformation. Then for every affine set $M \subset \mathbb{R}^n$, the image $TM := \{Tx \mid x \in M\}$ is an affine set in $\mathbb{R}^m$. Consequently, for every set $S \subset \mathbb{R}^n$, affine transformations preserve affine hulls in the sense that\n\n\[ \\operatorname{aff}(TS) = T(\\operatorname{aff} S). 
\end{thm}

\begin{thm}
Theorem 1.6. Let \(\{ b_0, b_1, \ldots, b_m \}\) and \(\{ b'_0, b'_1, \ldots, b'_m \}\) be affinely independent sets in \( R^n \). Then there exists a one-to-one affine transformation \( T \) of \( R^n \) onto itself, such that \( Tb_i = b'_i \) for \( i = 0, \ldots, m \). If \( m = n \), \( T \) is unique.
\end{thm}

proof:
\begin{proof}
Proof. Enlarging the given affinely independent sets if necessary, we can reduce the question to the case where \( m = n \). Then, as is well known in linear algebra, there exists a unique one-to-one linear transformation \( A \) of \( R^n \) onto itself carrying the basis \( b_1 - b_0, \ldots, b_n - b_0 \) of \( R_n \) onto the basis \( b'_1 - b'_0, \ldots, b'_n - b'_0 \). The desired affine transformation is then given by \( Tx = Ax + a \), where \( a = b'_0 - Ab_0 \). \(\|\)
\end{proof}

